import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { ApiService } from '../../core/api.service';
import { EventItem, Rsvp, RsvpStatus } from '../../core/models';

/**
 * GatherUp organizer per-event attendee list with a check-in toggle
 * (confirmed ↔ checkedIn). Loads live via ApiService.eventAttendees(id);
 * the toggle calls ApiService.toggleCheckin(id, userId).
 */
@Component({
  selector: 'app-organizer-event-attendees',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './organizer-event-attendees.component.html',
  styleUrl: './organizer-event-attendees.component.css',
})
export class OrganizerEventAttendeesComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);
  readonly eventId = signal('');

  readonly event = signal<EventItem[]>([]);

  readonly attendees = signal<Rsvp[]>([]);

  readonly current = computed<EventItem | undefined>(() => this.event()[0]);

  readonly confirmed = computed(() =>
    this.attendees().filter((a) => a.status === 'confirmed' || a.status === 'checkedIn'),
  );
  readonly waitlist = computed(() => this.attendees().filter((a) => a.status === 'waitlist'));
  readonly checkedInCount = computed(() =>
    this.attendees().filter((a) => a.status === 'checkedIn').length,
  );

  constructor(private route: ActivatedRoute, private api: ApiService) {}

  ngOnInit(): void {
    this.eventId.set(this.route.snapshot.paramMap.get('id') ?? '');
    this.loading.set(true);
    this.error.set(null);
    this.api.getEvent(this.eventId()).subscribe({
      next: (event) => this.event.set([event]),
      error: () => {},
    });
    this.api.eventAttendees(this.eventId()).subscribe({
      next: (attendees) => {
        this.attendees.set(attendees);
        this.loading.set(false);
      },
      error: () => {
        this.error.set('Could not load attendees. Please try again.');
        this.loading.set(false);
      },
    });
  }

  toggleCheckin(r: Rsvp): void {
    this.api.toggleCheckin(this.eventId(), r.userId).subscribe({
      next: (updated) => {
        this.attendees.update((list) =>
          list.map((a) => (a.id === r.id ? { ...a, status: updated.status } : a)),
        );
      },
      error: () => this.error.set('Could not update check-in. Please try again.'),
    });
  }

  badge(status: RsvpStatus): { cls: string; label: string } {
    switch (status) {
      case 'confirmed': return { cls: 'badge-ok', label: 'Confirmed' };
      case 'checkedIn': return { cls: 'badge-info', label: 'Checked in' };
      case 'waitlist': return { cls: 'badge-warn', label: 'Waitlisted' };
      default: return { cls: 'badge-muted', label: 'Cancelled' };
    }
  }
}
